head.script:
scwin.userClsCd = "";
scwin.hid_srchSelfTransCoCd = "";
scwin.hid_srchSelfTransCoNm = "";

scwin.onpageload = function() {
    scwin.userClsCd = $c.ses.getUserClsCd();
    scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");

    scwin.clntNo = $c.ses.getClntNo();
    scwin.clntNm = $c.ses.getClntNm();

    if (scwin.userClsCd == null) scwin.userClsCd = "";
};

scwin.onUdcCompleted = function() {
    udc_srchDate.setInitDate(scwin.vCurDate, scwin.vCurDate);

    const codeOptions = [
        { grpCd: "SD060", compID: "lc_srchImpExpClsCd", opt: {"allYn": "Y", "allCdVal": "", "allCdNm": "전체"} },
        { grpCd: "OP179", compID: "lc_srchRecptClsCd,gr_onReqInfo:admitClsCd", opt: {"allYn": "Y", "allCdVal": "", "allCdNm": "전체"} }
    ];
    $c.data.setCommonCode(codeOptions);

    ed_srchSelfTransCoCd.setFocus();

    if (scwin.userClsCd != "01") {
        ed_srchSelfTransCoCd.setValue(scwin.clntNo);
        txt_srchSelfTransCoNm.setValue(scwin.clntNm);
        $c.gus.cfDisableObjects([ed_srchSelfTransCoCd, txt_srchSelfTransCoNm]);
    } else {
        ed_srchSelfTransCoCd.setValue("");
        txt_srchSelfTransCoNm.setValue("");
        $c.gus.cfEnableObjects([ed_srchSelfTransCoCd, txt_srchSelfTransCoNm]);
    }
};

scwin.btn_fieldClear_onclick = function(e) {
    scwin.f_SetInitCondVal();
};

scwin.f_SetInitCondVal = function() {
    ed_srchSelfTransCoCd.setValue("");
    txt_srchSelfTransCoNm.setValue("");
    scwin.hid_srchSelfTransCoCd = "";
    scwin.hid_srchSelfTransCoNm = "";

    let toDay = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    udc_srchDate.setInitDate(toDay, toDay);

    lc_srchImpExpClsCd.setSelectedIndex(0);
    lc_srchRecptClsCd.setSelectedIndex(0);
};

scwin.f_OpenPopup = function(id, obj, param1, param2, pWinCloseTF, pWhere) {
    let rtnList = [];
    pWhere = ",LOGISCLNT2";
    rtnList = $c.gus.cfCommonPopUp(id, param1, param2, pWinCloseTF, null, null, null, null, pWhere, null, null, null, null);

    if (rtnList != null && rtnList[0] != "N/A") {
        for (let i = 0; i < obj.length; i++) {
            let target = obj[i];
            if (typeof target === "string") {
                if (target === "ed_srchSelfTransCoCd") {
                    ed_srchSelfTransCoCd.setValue(rtnList[i % 2]);
                } else if (target === "txt_srchSelfTransCoNm") {
                    txt_srchSelfTransCoNm.setValue(rtnList[i % 2]);
                } else if (target === "hid_srchSelfTransCoCd") {
                    scwin.hid_srchSelfTransCoCd = rtnList[i % 2];
                } else if (target === "hid_srchSelfTransCoNm") {
                    scwin.hid_srchSelfTransCoNm = rtnList[i % 2];
                }
            }
        }
    } else {
        for (let i = 0; i < obj.length; i++) {
            let target = obj[i];
            if (typeof target === "string") {
                if (target === "ed_srchSelfTransCoCd") {
                    ed_srchSelfTransCoCd.setValue("");
                } else if (target === "txt_srchSelfTransCoNm") {
                    txt_srchSelfTransCoNm.setValue("");
                } else if (target === "hid_srchSelfTransCoCd") {
                    scwin.hid_srchSelfTransCoCd = "";
                } else if (target === "hid_srchSelfTransCoNm") {
                    scwin.hid_srchSelfTransCoNm = "";
                }
            }
        }
    }
};

scwin.btn_retreive_onclick = function(e) {
    scwin.f_Retrieve();
};

scwin.f_Retrieve = async function() {
    if (!await $c.gus.cfValidate(ica_srchFromDate) || !await $c.gus.cfValidate(ica_srchToDate)) {
        return;
    }

    if (!$c.gus.cfIsAfterDate(ica_srchFromDate.getValue(), ica_srchToDate.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        ica_srchFromDate.setFocus();
        return;
    }

    if (ed_srchSelfTransCoCd.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["자가운송사"]);
        ed_srchSelfTransCoCd.setFocus();
        return;
    }

    if (!await $c.gus.cfValidate([tb_srchCond])) {
        return;
    }

    dma_srchCond.set("selfTransClntNo", ed_srchSelfTransCoCd.getValue());
    dma_srchCond.set("stDt", ica_srchFromDate.getValue());
    dma_srchCond.set("endDt", ica_srchToDate.getValue());
    dma_srchCond.set("impExpClsCd", lc_srchImpExpClsCd.getValue());
    dma_srchCond.set("admitClsCd", lc_srchRecptClsCd.getValue());

    $c.gus.cfShowDSWaitMsg(gr_onReqInfo);

    await $c.sbm.execute(sbm_retrieveOnRequestInfo);
};

scwin.sbm_retrieveOnRequestInfo_submitdone = async function(e) {
    $c.gus.cfHideDSWaitMsg(gr_onReqInfo);

    let rowCnt = ds_onReqInfo.getRowCount();
    if (rowCnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003);
    }

    spa_totalRows.setValue(rowCnt);
};

scwin.sbm_retrieveOnRequestInfo_submiterror = function(e) {
    $c.gus.cfHideDSWaitMsg(gr_onReqInfo);
    $c.gus.cfShowError(e);
};

scwin.btn_trigger1_onclick = async function(e) {
    scwin.f_On_Hire_Regist();
};

scwin.f_On_Hire_Regist = async function() {
    let tabTitle = "On-Hire반입(반납) 등록";
    let row = ds_onReqInfo.getRowPosition();
    if (row < 0) return;

    let selfTransClntNo = ed_srchSelfTransCoCd.getValue();
    let selfTransClntNm = txt_srchSelfTransCoNm.getValue();
    let odrNoVal = ds_onReqInfo.getCellData(row, "odrNo");
    let odrNo = (odrNoVal == null || odrNoVal == "undefined") ? "" : odrNoVal;

    if (ds_onReqInfo.getCellData(row, "impExpClsCd") != "D") {
        await $c.win.alert("On-Hire건만 가능합니다.");
        return;
    } else {
        let param = {
            selfTransClntNo: selfTransClntNo,
            selfTransClntNm: selfTransClntNm,
            odrNo: odrNo
        };
        $c.win.openMenu("On-Hire반입(반납) 등록", "/ui/ds/op/wrkrslts/cywrkrslts/op_301_02_19b.xml", "op_301_02_19b.xml", param);
    }
};

scwin.btn_trigger3_onclick = async function(e) {
    scwin.f_RegistOnReq();
};

scwin.f_RegistOnReq = async function() {
    let tabTitle = "수입/수출 상차 요청 등록";
    let row = ds_onReqInfo.getRowPosition();
    if (row < 0) return;

    let selfTransClntNoVal = ds_onReqInfo.getCellData(row, "selfTransClntNo");
    let selfTransClntNo = (selfTransClntNoVal == null || selfTransClntNoVal == "undefined") ? "" : selfTransClntNoVal;

    let selfTransClntNmVal = ds_onReqInfo.getCellData(row, "selfTransClntNm");
    let selfTransClntNm = (selfTransClntNmVal == null || selfTransClntNmVal == "undefined") ? "" : selfTransClntNmVal;

    let impExpClsCdVal = ds_onReqInfo.getCellData(row, "impExpClsCd");
    let impExpClsCd = (impExpClsCdVal == null || impExpClsCdVal == "undefined") ? "" : impExpClsCdVal;

    let onReqNoVal = ds_onReqInfo.getCellData(row, "onReqNo");
    let onReqDt = (onReqNoVal == null || onReqNoVal == "undefined") ? "" : onReqNoVal.substring(0, 8);

    let clntNo = selfTransClntNo;
    let clntNm = selfTransClntNm;

    if (impExpClsCd == "D") {
        await $c.win.alert("수출,수입건만 가능합니다.");
        return;
    } else {
        let param = {
            selfTransClntNo: selfTransClntNo,
            selfTransClntNm: selfTransClntNm,
            impExpClsCd: impExpClsCd,
            onReqDt: onReqDt,
            clntNo: clntNo,
            clntNm: clntNm
        };
        $c.win.openMenu(tabTitle, "/ui/ds/op/wrkrslts/cywrkrslts/op_301_02_01b.xml", "op_301_02_01b.xml", param);
    }
};

scwin.btn_trigger2_onclick = async function(e) {
    scwin.f_RegistOnExport();
};

scwin.f_RegistOnExport = async function() {
    let tabTitle = "반출(상차) 예정정보 등록";
    let row = ds_onReqInfo.getRowPosition();
    if (row < 0) return;

    let selfTransClntNoVal = ds_onReqInfo.getCellData(row, "selfTransClntNo");
    let selfTransClntNo = (selfTransClntNoVal == null || selfTransClntNoVal == "undefined") ? "" : selfTransClntNoVal;

    let selfTransClntNmVal = ds_onReqInfo.getCellData(row, "selfTransClntNm");
    let selfTransClntNm = (selfTransClntNmVal == null || selfTransClntNmVal == "undefined") ? "" : selfTransClntNmVal;

    let impExpClsCdVal = ds_onReqInfo.getCellData(row, "impExpClsCd");
    let impExpClsCd = (impExpClsCdVal == null || impExpClsCdVal == "undefined") ? "" : impExpClsCdVal;

    let onReqNoVal = ds_onReqInfo.getCellData(row, "onReqNo");
    let onReqDt = (onReqNoVal == null || onReqNoVal == "undefined") ? "" : onReqNoVal;

    let clntNo = selfTransClntNo;
    let clntNm = selfTransClntNm;

    if (impExpClsCd == "D") {
        await $c.win.alert("수출,수입건만 가능합니다.");
        return;
    } else {
        let param = {
            selfTransClntNo: selfTransClntNo,
            selfTransClntNm: selfTransClntNm,
            impExpClsCd: impExpClsCd,
            onReqDt: onReqDt,
            clntNo: clntNo,
            clntNm: clntNm
        };
        $c.win.openMenu(tabTitle, "/ui/ds/op/wrkrslts/cywrkrslts/op_301_02_09b.xml", "op_301_02_09b.xml", param);
    }
};

scwin.f_ErrorList = async function() {
    let row = ds_onReqInfo.getRowPosition();
    if (row < 0) return;

    if (ds_onReqInfo.getCellData(row, "admitClsCd") != "E") {
        await $c.win.alert("승인구분이 오류일 경우에만 조회가능합나다.");
        return;
    }
    if (ds_onReqInfo.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_008);
        return;
    }

    if (ds_onReqInfo.getRowPosition() < 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["상차요청번호"]);
        return;
    }

    ds_tempOnReqInfo.removeAll();

    let rowData = {};
    let colCount = ds_onReqInfo.getColumnCount();
    for (let c = 0; c < colCount; c++) {
        let colId = ds_onReqInfo.getColumnID(c);
        rowData[colId] = ds_onReqInfo.getCellData(row, colId);
    }
    ds_tempOnReqInfo.insertRow(0);
    for (let key in rowData) {
        ds_tempOnReqInfo.setCellData(0, key, rowData[key]);
    }

    let url = "/ui/ds/op/wrkrslts/cywrkrslts/op_301_02_14p.xml";
    await $c.win.openPopup(url, {
        width: 450,
        height: 420,
        modal: true,
        data: { ds_tempOnReqInfo: ds_tempOnReqInfo }
    });
};

scwin.f_grdHeiht = function(objGrdId, size) {
    let objGrd = $p.getComponentById(objGrdId);
    if (objGrd) {
        let strHeight = objGrd.getStyle("height");
        let intHeight = parseInt(strHeight.replace("px", ""));
        intHeight = intHeight + size;
        if (intHeight > 0) {
            objGrd.setStyle("height", intHeight + "px");
        }
    }
};

scwin.f_ResultsExcel = function() {
    $c.data.downloadGridViewExcel(gr_onReqInfo, {fileName: "상차요청승인현황(협력업체).xlsx", sheetName: "상차요청승인현황(협력업체)"});
};

scwin.ed_srchSelfTransCoCd_onblur = function(e) {
    if (ed_srchSelfTransCoCd.getValue().trim() == "" || (ed_srchSelfTransCoCd.getValue() == scwin.hid_srchSelfTransCoCd)) {
        return;
    }
    scwin.f_OpenPopup("retrieveClntList", ["ed_srchSelfTransCoCd", "txt_srchSelfTransCoNm", "hid_srchSelfTransCoCd", "hid_srchSelfTransCoNm"], ed_srchSelfTransCoCd.getValue(), "", "T", "");
    return;
};

scwin.txt_srchSelfTransCoNm_onchange = function(e) {
    if (txt_srchSelfTransCoNm.getValue().trim() == "" || (txt_srchSelfTransCoNm.getValue() == scwin.hid_srchSelfTransCoNm)) {
        return;
    }
    scwin.f_OpenPopup("retrieveClntList", ["ed_srchSelfTransCoCd", "txt_srchSelfTransCoNm", "hid_srchSelfTransCoCd", "hid_srchSelfTransCoNm"], "", txt_srchSelfTransCoNm.getValue(), "T", "");
    return;
};

scwin.gr_onReqInfo_oncelldblclick = function(rowIndex, columnIndex, columnId) {
    if (rowIndex >= 0) {
        let tabTitle = "수입/수출 상차 요청 등록";
        let tabTitle2 = "On-Hire 반입요청 등록";

        let selfTransClntNo = ds_onReqInfo.getCellData(rowIndex, "selfTransClntNo");
        let selfTransClntNm = ds_onReqInfo.getCellData(rowIndex, "selfTransClntNm");
        let impExpClsCd = ds_onReqInfo.getCellData(rowIndex, "impExpClsCd");
        let onReqNo = ds_onReqInfo.getCellData(rowIndex, "onReqNo");
        let onReqDt = (onReqNo != null && onReqNo != "" && onReqNo != "undefined") ? onReqNo.substring(0, 8) : "";

        let param = {
            selfTransClntNo: selfTransClntNo,
            selfTransClntNm: selfTransClntNm,
            impExpClsCd: impExpClsCd,
            onReqDt: onReqDt,
            onReqNo: onReqNo,
            clntNo: selfTransClntNo,
            clntNm: selfTransClntNm
        };

        if (impExpClsCd == "D") {
            $c.win.openMenu(tabTitle2, "/ui/ds/op/wrkrslts/cywrkrslts/op_301_02_24b.xml", "op_301_02_24b.xml", param);
        } else {
            $c.win.openMenu(tabTitle, "/ui/ds/op/wrkrslts/cywrkrslts/op_301_02_01b.xml", "op_301_02_01b.xml", param);
        }
    }
};

scwin.decode_bookingNo = function(data) {
    let row = ds_onReqInfo.getRowPosition();
    if (row < 0) return "";
    let impExpClsCd = ds_onReqInfo.getCellData(row, "impExpClsCd");
    let blNo = ds_onReqInfo.getCellData(row, "blNo");
    let bookingNo = ds_onReqInfo.getCellData(row, "bookingNo");
    if (impExpClsCd == "I") {
        return blNo || "";
    } else if (impExpClsCd == "O") {
        return bookingNo || "";
    } else if (impExpClsCd == "D") {
        return (blNo != null && blNo != "") ? blNo : (bookingNo || "");
    }
    return "";
};
